import React, { lazy, useEffect, useState } from 'react'
import { trackPromise } from 'react-promise-tracker'
import {
  CCard,
  CCardBody,
  CCardHeader,
  CCol,
  CRow,
  CTable,
  CTableBody,
  CTableDataCell,
  CTableHead,
  CTableHeaderCell,
  CTableRow,
  CBadge,
} from '@coreui/react'
import { getUser } from 'src/utils/Auth.js'

const WidgetsDropdown = lazy(() => import('../widgets/WidgetsDropdown.js'))

const Dashboard = () => {
  const [stat, setStat] = useState([])
  const user = getUser()
  // const random = (min, max) => {
  //   return Math.floor(Math.random() * (max - min + 1) + min)
  // }

  useEffect(() => {
    const getDashboardStat = async () => {
      const resFromServer = await fetchStat()
      resFromServer ? setStat(resFromServer) : setStat(null)
    }
    getDashboardStat()
  }, [])

  const fetchStat = async () => {
    const res = await trackPromise(
      fetch(
        `https://records.run.edu.ng/api/app/get_applicant_stat?userid=${user.id}&matno=${user.matric_number}`,
      ),
    )
    const data = await res.json()
    return data
  }

  return (
    <>
      <WidgetsDropdown
        success={stat.success_app}
        pending={stat.pend_app}
        failed={stat.failed_app}
      />
      <CRow>
        <CCol xs>
          <CCard className="mb-4">
            <CCardHeader>Recent Transactions</CCardHeader>
            <CCardBody>
              <br />
              <CTable align="middle" className="mb-0 border" hover responsive>
                <CTableHead color="light">
                  <CTableRow>
                    <CTableHeaderCell>Transaction ID</CTableHeaderCell>
                    <CTableHeaderCell className="text-center">Amount</CTableHeaderCell>
                    <CTableHeaderCell>Description</CTableHeaderCell>
                    <CTableHeaderCell className="text-center">Date</CTableHeaderCell>
                    <CTableHeaderCell className="text-center">Status</CTableHeaderCell>
                  </CTableRow>
                </CTableHead>
                {stat.payment && (
                  <CTableBody>
                    {stat.payment.map((item, index) => (
                      <CTableRow v-for="item in tableItems" key={index}>
                        <CTableDataCell>
                          <div>{item.rrr}</div>
                        </CTableDataCell>
                        <CTableDataCell className="text-center">
                          <div>{item.amount}</div>
                        </CTableDataCell>
                        <CTableDataCell>
                          <div>{item.destination}</div>
                        </CTableDataCell>
                        <CTableDataCell className="text-center">
                          <div>{new Date(item.created_at).toDateString()}</div>
                        </CTableDataCell>
                        <CTableDataCell className="text-center">
                          {item.status_msg === 'pending' ? (
                            <CBadge color="danger" shape="rounded-pill">
                              {item.status_msg}
                            </CBadge>
                          ) : (
                            <CBadge color="success" shape="rounded-pill">
                              {item.status_msg}
                            </CBadge>
                          )}
                        </CTableDataCell>
                      </CTableRow>
                    ))}
                  </CTableBody>
                )}
              </CTable>
            </CCardBody>
          </CCard>
        </CCol>
      </CRow>
    </>
  )
}

export default Dashboard
